import React, { useState, useEffect } from 'react';

const CouponGenerator = () => {
  const [coupons, setCoupons] = useState([]);
  const [newCoupon, setNewCoupon] = useState({
    code: '',
    discountPercent: 100,
    description: '',
    maxUses: 100,
    expiresAt: '',
    isActive: true
  });

  // Load existing coupons on component mount
  useEffect(() => {
    loadExistingCoupons();
  }, []);

  const generateCode = () => {
    const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
    let result = '';
    for (let i = 0; i < 8; i++) {
      result += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    setNewCoupon(prev => ({ ...prev, code: result }));
  };

  const createCoupon = () => {
    if (!newCoupon.code || !newCoupon.description) {
      alert('Please fill in all required fields');
      return;
    }

    // Check if code already exists
    const existingCoupons = JSON.parse(localStorage.getItem('adminCoupons') || '[]');
    if (existingCoupons.find(c => c.code === newCoupon.code.toUpperCase())) {
      alert('This coupon code already exists!');
      return;
    }

    const coupon = {
      ...newCoupon,
      code: newCoupon.code.toUpperCase(),
      id: Date.now(),
      createdAt: new Date().toISOString(),
      usedCount: 0,
      isActive: true
    };

    const updatedCoupons = [...existingCoupons, coupon];
    setCoupons(updatedCoupons);
    
    // Save to localStorage and update available coupons in checkout
    localStorage.setItem('adminCoupons', JSON.stringify(updatedCoupons));
    updateCheckoutCoupons(updatedCoupons);
    
    // Reset form
    setNewCoupon({
      code: '',
      discountPercent: 100,
      description: '',
      maxUses: 100,
      expiresAt: '',
      isActive: true
    });

    alert(`🎉 Coupon "${coupon.code}" created successfully!`);
  };

  const loadExistingCoupons = () => {
    const existing = JSON.parse(localStorage.getItem('adminCoupons') || '[]');
    setCoupons(existing);
  };

  const updateCheckoutCoupons = (couponList) => {
    // Convert array to object format for checkout component
    const checkoutCoupons = {};
    couponList.forEach(coupon => {
      if (coupon.isActive) {
        checkoutCoupons[coupon.code] = {
          discountPercent: coupon.discountPercent,
          description: coupon.description
        };
      }
    });
    
    // Save to localStorage for checkout to use
    localStorage.setItem('availableCoupons', JSON.stringify(checkoutCoupons));
  };

  const deleteCoupon = (couponId) => {
    if (window.confirm('Are you sure you want to delete this coupon?')) {
      const updatedCoupons = coupons.filter(c => c.id !== couponId);
      setCoupons(updatedCoupons);
      localStorage.setItem('adminCoupons', JSON.stringify(updatedCoupons));
      updateCheckoutCoupons(updatedCoupons);
    }
  };

  const toggleCouponStatus = (couponId) => {
    const updatedCoupons = coupons.map(coupon => 
      coupon.id === couponId 
        ? { ...coupon, isActive: !coupon.isActive }
        : coupon
    );
    setCoupons(updatedCoupons);
    localStorage.setItem('adminCoupons', JSON.stringify(updatedCoupons));
    updateCheckoutCoupons(updatedCoupons);
  };

  return (
    <div className="coupon-generator">
      <div className="generator-form">
        <h3>Create New Coupon</h3>
        
        <div className="form-group">
          <label>Coupon Code: *</label>
          <div className="code-input-group">
            <input
              type="text"
              value={newCoupon.code}
              onChange={(e) => setNewCoupon(prev => ({ ...prev, code: e.target.value }))}
              placeholder="e.g., LAUNCH100"
              maxLength="20"
            />
            <button type="button" onClick={generateCode} className="btn-generate">
              🎲 Generate
            </button>
          </div>
        </div>

        <div className="form-group">
          <label>Discount Percentage: *</label>
          <input
            type="number"
            value={newCoupon.discountPercent}
            onChange={(e) => setNewCoupon(prev => ({ ...prev, discountPercent: parseInt(e.target.value) }))}
            min="1"
            max="100"
          />
        </div>

        <div className="form-group">
          <label>Description: *</label>
          <input
            type="text"
            value={newCoupon.description}
            onChange={(e) => setNewCoupon(prev => ({ ...prev, description: e.target.value }))}
            placeholder="e.g., 100% OFF - Free Ad Space"
          />
        </div>

        <div className="form-group">
          <label>Maximum Uses: *</label>
          <input
            type="number"
            value={newCoupon.maxUses}
            onChange={(e) => setNewCoupon(prev => ({ ...prev, maxUses: parseInt(e.target.value) }))}
            min="1"
          />
        </div>

        <div className="form-group">
          <label>Expiry Date:</label>
          <input
            type="datetime-local"
            value={newCoupon.expiresAt}
            onChange={(e) => setNewCoupon(prev => ({ ...prev, expiresAt: e.target.value }))}
          />
        </div>

        <button onClick={createCoupon} className="btn-create">
          🎫 Create Coupon
        </button>
      </div>

      <div className="coupons-management">
        <div className="management-header">
          <h3>Existing Coupons ({coupons.length})</h3>
          <button onClick={loadExistingCoupons} className="btn-refresh">
            🔄 Refresh
          </button>
        </div>

        {coupons.length === 0 ? (
          <p className="no-coupons">No coupons created yet.</p>
        ) : (
          <div className="coupons-list">
            {coupons.map(coupon => (
              <div key={coupon.id} className={`coupon-item ${!coupon.isActive ? 'inactive' : ''}`}>
                <div className="coupon-header">
                  <span className="coupon-code">{coupon.code}</span>
                  <div className="coupon-actions">
                    <button 
                      onClick={() => toggleCouponStatus(coupon.id)}
                      className={`btn-status ${coupon.isActive ? 'active' : 'inactive'}`}
                    >
                      {coupon.isActive ? '✅' : '❌'}
                    </button>
                    <button 
                      onClick={() => deleteCoupon(coupon.id)}
                      className="btn-delete"
                    >
                      🗑️
                    </button>
                  </div>
                </div>
                <div className="coupon-details">
                  <strong>{coupon.discountPercent}% OFF</strong> - {coupon.description}
                </div>
                <div className="coupon-meta">
                  <span>Uses: {coupon.usedCount || 0}/{coupon.maxUses}</span>
                  {coupon.expiresAt && (
                    <span> | Expires: {new Date(coupon.expiresAt).toLocaleDateString()}</span>
                  )}
                  <span> | Created: {new Date(coupon.createdAt).toLocaleDateString()}</span>
                </div>
                <div className="coupon-status">
                  Status: {coupon.isActive ? '🟢 Active' : '🔴 Inactive'}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default CouponGenerator;
